    try {
        if (silentPlayer == null) {
            silentPlayer = MediaPlayer.create(this, Settings.System.DEFAULT_NOTIFICATION_URI)
            silentPlayer?.setVolume(0f, 0f)
            silentPlayer?.isLooping = true
