function jumpToElement(element, tabId, navIndex) {
    console.group(`[JumpEngine] Triggered: ${tabId}`);
    if (!element) {
        console.error("[JumpEngine] Failed: Element is null");
        console.groupEnd();
        return;
    }

    // 1. Force Tab Switch
    const navItems = document.querySelectorAll('.nav-item');
    switchTab(tabId, navItems[navIndex]);
    console.log("[JumpEngine] Tab switched.");

    const scrollContainer = document.querySelector('.main-view');

    let attempts = 0;
    const scrollLogic = () => {
        attempts++;

        // Calculate position relative to the scroll container
        // We iterate up the offsetParents until we hit the container
        let offsetTop = 0;
        let curr = element;
        while (curr && curr !== scrollContainer) {
            offsetTop += curr.offsetTop;
            curr = curr.offsetParent;
        }

        console.log(`[JumpEngine] Attempt ${attempts}: Calculated offsetTop as ${offsetTop}`);

        if (offsetTop > 0 || attempts > 3) {
            // Center the element: targetTop = offsetTop - (containerHeight / 2) + (elementHeight / 2)
            const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);

            console.log(`[JumpEngine] Executing scroll to: ${targetScroll}`);

            scrollContainer.scrollTo({
                top: targetScroll,
                behavior: 'smooth'
            });

            // Visual Feedback
            element.style.transition = 'all 0.5s ease';
            const oldBg = element.style.backgroundColor;
            const oldShadow = element.style.boxShadow;
            const oldBorder = element.style.border;

            element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
            element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
            element.style.border = '2px solid var(--primary)';

            setTimeout(() => {
                element.style.backgroundColor = oldBg;
                element.style.boxShadow = oldShadow;
                element.style.border = oldBorder;
            }, 3000);

            console.groupEnd();
        } else {
            // If offset is still 0, the tab content might still be hidden/rendering
            setTimeout(scrollLogic, 150);
        }
    };

    // Wait for tab transition animation before starting logic
    setTimeout(scrollLogic, 250);
}

