async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
    console.group(`[DeepJump] Target: ${selector} in ${tabId}`);

    const navItems = document.querySelectorAll('.nav-item');
    switchTab(tabId, navItems[navIndex]);

    const scrollContainer = document.querySelector('.main-view');
    let retryCount = 0;
    const MAX_RETRIES = 5;

    const attemptNavigation = async () => {
        const element = document.querySelector(selector);

        if (element) {
            console.log("[DeepJump] Element found. Scrolling...");

            // Wait for any tab transition animations
            await new Promise(r => setTimeout(r, 300));

            let offsetTop = 0;
            let curr = element;
            while (curr && curr !== scrollContainer) {
                offsetTop += curr.offsetTop;
                curr = curr.offsetParent;
            }

            const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
            scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });

            // Visual Highlight
            element.style.transition = 'all 0.5s ease';
            element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
            element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
            setTimeout(() => {
                element.style.backgroundColor = '';
                element.style.boxShadow = '';
            }, 3000);

            console.groupEnd();
            return true;
        }

        if (retryCount < MAX_RETRIES && loadMoreFn) {
            console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
            retryCount++;
            showGlobalToast("🔍 Searching deeper...");

            await loadMoreFn(); 
            await new Promise(r => setTimeout(r, 800)); // Wait for render
            return attemptNavigation();
        }

        console.error("[DeepJump] Failed: Element not found after retries.");
        showGlobalToast("Entry not found in recent history.", true);
        console.groupEnd();
        return false;
    };

    setTimeout(attemptNavigation, 100);
}

