async function toggleFavorite(targetId, category, metadata) {
    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'toggle_favorite', target_id: targetId, category, metadata })
        });
        const data = await res.json();
        if (data.success) {
            showGlobalToast(data.favorited ? "⭐ Added to Favorites" : "Removed from Favorites");
            // Visual feedback in UI - simpler than full re-render
            const btns = document.querySelectorAll(`.favorite-btn[onclick*="'${targetId}'"]`);
            btns.forEach(btn => btn.style.color = data.favorited ? 'var(--dev)' : '#555');
        }
    } catch(e) { showGlobalToast("Error saving favorite", true); }
}

async function openFavorites() {
    const overlay = document.getElementById('favorites-overlay');
    const list = document.getElementById('favorites-list');
    overlay.classList.add('active');
    list.innerHTML = '<div style="text-align:center; padding:20px;">⭐ Loading Favourites...</div>';

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'fetch_favorites' })
        });
        const data = await res.json();

        if (!data.favorites || data.favorites.length === 0) {
            list.innerHTML = '<div style="text-align:center; padding:40px; color:#666;">No items saved yet. Star items in Terminal, History, or CI/CD to see them here.</div>';
            return;
        }

        list.innerHTML = data.favorites.map(fav => {
            const m = fav.metadata;
            const typeColor = fav.category === 'Patch' ? 'var(--ai-accent)' : (fav.category === 'Commit' ? 'var(--primary)' : 'var(--prod)');
            return `
            <div class="card" style="padding:12px; margin-bottom:10px; cursor:pointer;" onclick="jumpToFavorite('${fav.target_id}', '${fav.category}')">
                <div class="flex-between">
                    <span class="status-pill" style="background:${typeColor}22; color:${typeColor};">${fav.category}</span>
                    <small style="color:#666;">${new Date(fav.created_at).toLocaleDateString()}</small>
                </div>
                <div style="margin-top:8px; font-weight:600; font-size:13px; color:#eee;">${m.conduit_id ? '#' + m.conduit_id + ' ' : ''}${m.title}</div>
                <div style="font-size:10px; color:#444; font-family:'JetBrains Mono'; margin-top:4px;">${fav.target_id.substring(0, 10)}...</div>
            </div>`;
        }).join('');
    } catch(e) { list.innerHTML = 'Error loading favorites.'; }
}

function jumpToFavorite(id, category) {
    document.getElementById('favorites-overlay').classList.remove('active');
    if (category === 'Patch') {
        jumpToElement(`.log-entry[data-commit-sha="${id}"]`, 'tab-patcher', 1, loadMoreLogs);
    } else if (category === 'Commit') {
        jumpToElement(`.version-item[data-commit-sha="${id}"]`, 'tab-history', 3, loadMoreHistory);
    } else if (category === 'Build') {
        jumpToElement(`#workflow-list div[data-commit-sha="${id}"]`, 'tab-cicd', 4, loadMoreWorkflows);
    }
}

