package com.universal.app

import android.app.*
import android.content.*
import android.os.*
import android.speech.tts.TextToSpeech
import androidx.core.app.NotificationCompat
import androidx.lifecycle.LifecycleService
import androidx.lifecycle.lifecycleScope
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import kotlinx.coroutines.*
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File
import java.util.*

class MainPollingService : LifecycleService() {
    private val client = OkHttpClient()
    private lateinit var tts: TextToSpeech
    private val processedIds = mutableSetOf<String>()
    private val SUPABASE_URL = "https://xvldfsmxskhemkslsbym.supabase.co"
    private val ANON_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh2bGRmc214c2toZW1rc2xzYnltIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjI2ODgxNzksImV4cCI6MjA3ODI2NDE3OX0.5arqrx8Tt7v-hpXpo_ncoK4IX8th9IibxAuv93SSoOU"

    override fun onCreate() {
        super.onCreate()
        startForeground(1, createNotification())
        tts = TextToSpeech(this) { }
        loadProcessedIds()
        startPolling()
    }

    private fun createNotification(): Notification {
        val channelId = "polling_channel"
        val manager = getSystemService(NotificationManager::class.java)
        manager.createNotificationChannel(NotificationChannel(channelId, "Polling", NotificationManager.IMPORTANCE_LOW))
        return NotificationCompat.Builder(this, channelId)
            .setContentTitle("System Active")
            .setContentText("Watching for updates...")
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .build()
    }

    private fun startPolling() {
        lifecycleScope.launch(Dispatchers.IO) {
            while (isActive) {
                try {
                    fetchData()
                } catch (e: Exception) { e.printStackTrace() }
                delay(5000)
            }
        }
    }

    private fun fetchData() {
        val request = Request.Builder()
            .url("$SUPABASE_URL/rest/v1/processed_images?status=eq.completed&select=*")
            .addHeader("apikey", ANON_KEY)
            .addHeader("Authorization", "Bearer $ANON_KEY")
            .build()

        client.newCall(request).execute().use { response ->
            val body = response.body?.string() ?: return
            val items: List<Map<String, Any>> = Gson().fromJson(body, object : TypeToken<List<Map<String, Any>>>() {}.type)

            items.forEach { item ->
                val id = item["id"].toString()
                if (id !in processedIds) {
                    processSolution(id, item["solution_json"])
                    processedIds.add(id)
                    saveProcessedIds()
                }
            }
        }
    }

    private fun processSolution(id: String, solutionData: Any?) {
        val types = listOf("mc", "tf", "fill", "ma", "sa", "wo")
        val solutions = if (solutionData != null) {
            val json = Gson().toJson(solutionData)
            val wrapper: Map<String, List<Map<String, Any>>> = Gson().fromJson(json, object : TypeToken<Map<String, List<Map<String, Any>>>>() {}.type)
            wrapper["solutions"] ?: emptyList()
        } else emptyList()

        types.forEach { type ->
            val filtered = solutions.filter { it["type"] == type }
            val text = if (filtered.isEmpty()) {
                "Section $type is not available."
            } else {
                filtered.joinToString(" ") { sol ->
                    val num = sol["number"].toString()
                    val ans = sol["answer"].toString()
                    val steps = (sol["steps"] as? List<*>)?.joinToString(". ") ?: ""
                    "Question number $num, $ans. $steps"
                }
            }
            synthesize(id, type, text)
        }
    }

    private fun synthesize(id: String, type: String, text: String) {
        val folder = File(getExternalFilesDir(null), "audios")
        if (!folder.exists()) folder.mkdirs()
        val file = File(folder, "${id}_${type}.wav")
        tts.synthesizeToFile(text, null, file, "${id}_${type}")
    }

    private fun loadProcessedIds() {
        val prefs = getSharedPreferences("app_prefs", MODE_PRIVATE)
        processedIds.addAll(prefs.getStringSet("ids", emptySet()) ?: emptySet())
    }

    private fun saveProcessedIds() {
        getSharedPreferences("app_prefs", MODE_PRIVATE).edit()
            .putStringSet("ids", processedIds).apply()
    }
}

package com.universal.app

import android.content.*
import android.net.Uri
import android.os.*
import android.provider.Settings
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import android.media.MediaPlayer
import java.io.File

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContent {
            var hasPermissions by remember { mutableStateOf(false) }

            LaunchedEffect(Unit) {
                while(true) {
                    hasPermissions = isAccessibilityEnabled() && isBatteryIgnored()
                    delay(2000)
                }
            }

            if (!hasPermissions) {
                SetupScreen()
            } else {
                DashboardScreen()
            }
        }
    }

    private fun isAccessibilityEnabled(): Boolean {
        val pref = Settings.Secure.getString(contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES)
        return pref?.contains(packageName) == true
    }

    private fun isBatteryIgnored(): Boolean {
        val pm = getSystemService(PowerManager::class.java)
        return pm.isIgnoringBatteryOptimizations(packageName)
    }

    @Composable
    fun SetupScreen() {
        Column(Modifier.fillMaxSize().padding(16.dp), verticalArrangement = Arrangement.Center) {
            Text("System Requirements", style = MaterialTheme.typography.headlineMedium)
            Spacer(Modifier.height(20.dp))
            Button(onClick = { startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)) }) {
                Text("Enable Accessibility")
            }
            Button(onClick = { 
                val intent = Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS)
                intent.data = Uri.parse("package:$packageName")
                startActivity(intent)
            }) {
                Text("Ignore Battery Optimization")
            }
        }
    }

    @Composable
    fun DashboardScreen() {
        var audioFiles by remember { mutableStateOf(listOf<File>()) }

        LaunchedEffect(Unit) {
            val intent = Intent(this@MainActivity, MainPollingService::class.java)
            startForegroundService(intent)
            while(true) {
                val folder = File(getExternalFilesDir(null), "audios")
                audioFiles = folder.listFiles()?.toList() ?: emptyList()
                delay(3000)
