import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import android.media.MediaPlayer
import java.io.File

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContent {
            var hasPermissions by remember { mutableStateOf(false) }

            LaunchedEffect(Unit) {
                while(true) {
                    hasPermissions = isAccessibilityEnabled() && isBatteryIgnored()
                    delay(2000)
                }
            }

            if (!hasPermissions) {
                SetupScreen()
            } else {
                DashboardScreen()
            }
        }
    }

    private fun isAccessibilityEnabled(): Boolean {
        val pref = Settings.Secure.getString(contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES)
        return pref?.contains(packageName) == true
    }

    private fun isBatteryIgnored(): Boolean {
        val pm = getSystemService(PowerManager::class.java)
        return pm.isIgnoringBatteryOptimizations(packageName)
    }

    @Composable
    fun SetupScreen() {
        Column(Modifier.fillMaxSize().padding(16.dp), verticalArrangement = Arrangement.Center) {
            Text("System Requirements", style = MaterialTheme.typography.headlineMedium)
            Spacer(Modifier.height(20.dp))
            Button(onClick = { startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS)) }) {
                Text("Enable Accessibility")
            }
            Button(onClick = { 
                val intent = Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS)
                intent.data = Uri.parse("package:$packageName")
                startActivity(intent)
            }) {
                Text("Ignore Battery Optimization")
            }
        }
    }

    @Composable
    fun DashboardScreen() {
        var audioFiles by remember { mutableStateOf(listOf<File>()) }

        LaunchedEffect(Unit) {
            val intent = Intent(this@MainActivity, MainPollingService::class.java)
            startForegroundService(intent)
            while(true) {
                val folder = File(getExternalFilesDir(null), "audios")
                audioFiles = folder.listFiles()?.toList() ?: emptyList()
                delay(3000)
            }
        }

        Column(Modifier.fillMaxSize().padding(16.dp)) {
            Text("Audio Dashboard", style = MaterialTheme.typography.headlineMedium)
            LazyColumn(Modifier.weight(1f)) {
                items(audioFiles) { file ->
                    Button(
                        onClick = { playAudio(file) },
                        modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp)
                    ) {
                        Text(file.name)
                    }
                }
            }
        }
    }

    private fun playAudio(file: File) {
        MediaPlayer().apply {
            setDataSource(file.absolutePath)
            prepare()
            start()
        }
    }
}

