object DebugLogger {
    val logs = mutableStateListOf<String>()
    private val timeFormat = SimpleDateFormat("HH:mm:ss", Locale.getDefault())

    fun log(tag: String, message: String) {
        val time = timeFormat.format(Date())
        logs.add(0, "[$time] $tag: $message")
